def original(X):
    if X > 71:
        return None  # nuw violation - undefined
    sub = 71 - X
    and_val = sub & (-8 & 0xFFFFFFFFFFFFFFFF)  # 64-bit -8
    result = (64 - and_val) & 0xFFFFFFFFFFFFFFFF
    return result

def formula1(X):
    return X & 120

def formula2(X):
    return X & (-8 & 0xFFFFFFFFFFFFFFFF)

print("Checking X from 0 to 100:")
mismatch = False
for X in range(0, 100):
    o = original(X)
    if o is None:
        continue
    f1 = formula1(X)
    f2 = formula2(X)
    if o != f1:
        print(f"X={X}: orig={o}, F1={f1} MISMATCH!")
        mismatch = True
    if o != f2:
        print(f"X={X}: orig={o}, F2={f2} MISMATCH!")
        mismatch = True

